function playSound(key) {
  if (!unlockedAudio) return;
  const list = sounds[key];
  const audio = list[Math.floor(Math.random() * list.length)];
  audio.currentTime = 0;
  void audio.play().catch(() => {
  });
}
function unlockAudio() {
  if (unlockedAudio) return;
  unlockedAudio = true;
  for (const audio of Object.values(sounds).flat()) {
    audio.muted = true;
    void audio.play().then(() => {
      audio.pause();
      audio.currentTime = 0;
      audio.muted = false;
    }).catch(() => {
      audio.muted = false;
    });
  }
}
function addStaticSegment(a3, b3, restitution = 0.35, friction = 0.1) {
  const body = world.createRigidBody(cg.RigidBodyDesc.fixed());
  world.createCollider(
    cg.ColliderDesc.segment({ x: a3[0], y: a3[1] }, { x: b3[0], y: b3[1] }).setRestitution(restitution).setFriction(friction),
    body
  );
}
function addBumper(x3, y3, radius, points) {
  const body = world.createRigidBody(cg.RigidBodyDesc.fixed().setTranslation(x3, y3));
  const collider = world.createCollider(
    cg.ColliderDesc.ball(radius).setRestitution(1.24).setFriction(0).setActiveEvents(cg.ActiveEvents.COLLISION_EVENTS),
    body
  );
  colliderTags.set(collider.handle, { type: "bumper", points });
  return { x: x3, y: y3, radius };
}
function addSensorRect(x3, y3, hw, hh, tag) {
  const body = world.createRigidBody(cg.RigidBodyDesc.fixed().setTranslation(x3, y3));
  const collider = world.createCollider(
    cg.ColliderDesc.cuboid(hw, hh).setSensor(true).setActiveEvents(cg.ActiveEvents.COLLISION_EVENTS),
    body
  );
  colliderTags.set(collider.handle, tag);
  return collider.handle;
}
function addSensorBall(x3, y3, radius, tag) {
  const body = world.createRigidBody(cg.RigidBodyDesc.fixed().setTranslation(x3, y3));
  const collider = world.createCollider(
    cg.ColliderDesc.ball(radius).setSensor(true).setActiveEvents(cg.ActiveEvents.COLLISION_EVENTS),
    body
  );
  colliderTags.set(collider.handle, tag);
  return collider.handle;
}
