function createBall(inLauncher) {
  const body = world.createRigidBody(
    cg.RigidBodyDesc.dynamic().setTranslation(inLauncher ? LAUNCH_LANE_CENTER : 458, inLauncher ? LAUNCH_REST_Y : 205).setLinearDamping(0.12).setAngularDamping(0.2).setCcdEnabled(true)
  );
  const collider = world.createCollider(
    cg.ColliderDesc.ball(BALL_RADIUS).setDensity(0.8).setRestitution(0.72).setFriction(0.02).setActiveEvents(cg.ActiveEvents.COLLISION_EVENTS),
    body
  );
  colliderTags.set(collider.handle, { type: "ball" });
  return body;
}
function replaceBall(inLauncher) {
  const existing = ballBody.collider(0);
  if (existing) colliderTags.delete(existing.handle);
  world.removeRigidBody(ballBody);
  ballBody = createBall(inLauncher);
  ballInLauncher = inLauncher;
  ballInProtectedLaunchLane = false;
  drainPending = false;
}
function updateHud() {
  scoreEl.textContent = String(score);
  ballsEl.textContent = String(ballsRemaining);
  highScoreEl.textContent = String(highScore);
}
function setNameRowVisible(visible) {
  nameRow.classList.toggle("hidden", !visible);
  if (visible) nameInput.focus();
}
function updateOverlay() {
  if (running && !gameOver) {
    overlay.hidden = true;
    return;
  }
  overlay.hidden = false;
  if (gameOver) {
    overlayActionBtn.textContent = "Play again";
    overlayMessage.textContent = `Game over. Springfield score: ${score}.`;
  } else if (ballInLauncher) {
    overlayActionBtn.textContent = running ? "Launch ball" : "Start game";
    overlayMessage.textContent = "Tap launch to send the ball into Springfield.";
  } else {
    overlayActionBtn.textContent = "Resume";
    overlayMessage.textContent = "Keep the ball alive and chase extra balls.";
  }
}
function triggerBurst(color, x3, y3) {
  const burst = new Graphics();
  burst.circle(0, 0, 24).stroke({ color, width: 7, alpha: 0.8 });
  burst.position.set(x3, y3);
  fxLayer.addChild(burst);
  const started = performance.now();
  const tick = () => {
    const elapsed = (performance.now() - started) / 260;
    burst.scale.set(1 + elapsed * 1.8);
    burst.alpha = Math.max(0, 1 - elapsed);
    if (elapsed >= 1) {
      app.ticker.remove(tick);
      burst.destroy();
      return;
    }
  };
  app.ticker.add(tick);
}
function awardPoints(points) {
  score += points;
  highScore = Math.max(highScore, score);
  for (let i3 = awardedExtraBalls; i3 < EXTRA_BALL_THRESHOLDS.length; i3 += 1) {
    if (score >= EXTRA_BALL_THRESHOLDS[i3]) {
      ballsRemaining += 1;
      awardedExtraBalls += 1;
      triggerBurst(i3 % 2 === 0 ? 16736972 : 7595519, 310, 330);
    }
  }
  updateHud();
}
function launchBall() {
  if (!running) {
    running = true;
  }
  if (!ballInLauncher) return;
  ballBody.setTranslation({ x: LAUNCH_LANE_CENTER, y: LAUNCH_REST_Y }, true);
  ballBody.setLinvel({ x: 0, y: -3200 }, true);
  ballInLauncher = false;
  ballInProtectedLaunchLane = true;
  updateOverlay();
  playSound("launch");
}
function drainBall() {
  if (drainPending) return;
  drainPending = true;
  playSound("drain");
  ballsRemaining -= 1;
  updateHud();
  if (ballsRemaining <= 0) {
    running = false;
    gameOver = true;
    setNameRowVisible(true);
    submitBtn.disabled = score <= 0 || lastSubmittedScore === score;
    updateOverlay();
    return;
  }
  window.setTimeout(() => {
    replaceBall(true);
    running = true;
    updateOverlay();
  }, 900);
}
function handleCollision(tag, handle) {
  const pos = ballBody.translation();
  if (tag.type === "bumper") {
    awardPoints(tag.points);
    const direction = pos.x < VIRTUAL_WIDTH / 2 ? -1 : 1;
    ballBody.applyImpulse({ x: direction * 160, y: -140 }, true);
    triggerBurst(16736972, pos.x, pos.y);
    playSound("bumper");
    return;
  }
  if (tag.type === "slingshot") {
    awardPoints(tag.points);
    const direction = pos.x < VIRTUAL_WIDTH / 2 ? 1 : -1;
    ballBody.applyImpulse({ x: direction * 160, y: -160 }, true);
    playSound("lane");
    return;
  }
  if (tag.type === "lane") {
    awardPoints(tag.points);
    if (handle === laneHandles[0]) leftLaneLit = true;
    if (handle === laneHandles[1]) rightLaneLit = true;
    drawTable();
    playSound("lane");
    return;
  }
  if (tag.type === "drain") {
    drainBall();
  }
}
function stepPhysics(deltaMs) {
  accumulator += deltaMs / 1e3;
  while (accumulator >= FIXED_STEP) {
    accumulator -= FIXED_STEP;
    leftFlipperBody.setNextKinematicRotation(leftPressed ? leftFlipperActive : leftFlipperRest);
    rightFlipperBody.setNextKinematicRotation(rightPressed ? rightFlipperActive : rightFlipperRest);
    world.step(eventQueue);
    eventQueue.drainCollisionEvents((h1, h22, started) => {
      if (!started) return;
      const tag1 = colliderTags.get(h1);
      const tag2 = colliderTags.get(h22);
      if (tag1?.type === "ball" && tag2) handleCollision(tag2, h22);
      if (tag2?.type === "ball" && tag1) handleCollision(tag1, h1);
    });
    const pos = ballBody.translation();
    if (ballInLauncher) {
      ballBody.setTranslation({ x: LAUNCH_LANE_CENTER, y: LAUNCH_REST_Y }, true);
      ballBody.setLinvel({ x: 0, y: 0 }, true);
      ballBody.setAngvel(0, true);
    }
    if (ballInProtectedLaunchLane) {
      const currentVel = ballBody.linvel();
      ballBody.setTranslation({ x: LAUNCH_LANE_CENTER, y: pos.y }, true);
      ballBody.setLinvel({ x: 0, y: Math.min(currentVel.y, -3e3) }, true);
      ballBody.setAngvel(0, true);
      if (pos.y <= LAUNCH_GATE_Y) {
        ballInProtectedLaunchLane = false;
        ballBody.setLinvel({ x: -620, y: -2480 }, true);
      }
    } else if (!ballInLauncher && pos.x > LAUNCH_LANE_LEFT + 4 && pos.x < LAUNCH_LANE_RIGHT - 4) {
      if (pos.y < LAUNCH_GATE_Y) {
        ballBody.applyImpulse({ x: -110, y: -22 }, true);
      }
      if (pos.x < LAUNCH_LANE_LEFT + BALL_RADIUS + 3) {
        ballBody.setTranslation({ x: LAUNCH_LANE_LEFT + BALL_RADIUS + 4, y: pos.y }, true);
      } else if (pos.x > LAUNCH_LANE_RIGHT - BALL_RADIUS - 3) {
        ballBody.setTranslation({ x: LAUNCH_LANE_RIGHT - BALL_RADIUS - 4, y: pos.y }, true);
      }
    }
    if (!ballInLauncher && pos.y > VIRTUAL_HEIGHT + 100) {
      drainBall();
    }
    if (leftPressed && pos.y > 770 && pos.x < 300) {
      ballBody.applyImpulse({ x: 22, y: -34 }, true);
    }
    if (rightPressed && pos.y > 770 && pos.x > 320) {
      ballBody.applyImpulse({ x: -22, y: -34 }, true);
    }
  }
}
function drawFlipper(graphic, x3, y3, rotation, isLeft) {
  graphic.clear();
  graphic.position.set(x3, y3);
  graphic.rotation = rotation;
  graphic.roundRect(isLeft ? 0 : -116, -14, 116, 28, 14).fill({ color: isLeft ? 16736972 : 7595519 }).stroke({ color: 16777215, width: 4 });
  graphic.circle(0, 0, 18).fill({ color: 16777215 }).stroke({ color: 3621230, width: 4 });
}
function makeLight(x3, y3, lit) {
  const g3 = new Graphics();
  g3.circle(x3, y3, 20).fill({ color: lit ? 16736973 : 16777215, alpha: lit ? 1 : 0.35 }).stroke({ color: 3621230, width: 3 });
  return g3;
}
function drawStar(g3, x3, y3, r1, r22, points, color) {
  const step = Math.PI / points;
  g3.moveTo(x3, y3 - r1);
  for (let i3 = 1; i3 < points * 2; i3 += 1) {
    const radius = i3 % 2 === 0 ? r1 : r22;
    const angle = -Math.PI / 2 + i3 * step;
    g3.lineTo(x3 + Math.cos(angle) * radius, y3 + Math.sin(angle) * radius);
  }
  g3.closePath();
  g3.fill({ color });
}
